import React, { useEffect, useMemo } from "react";
import { useDispatch, useSelector } from "react-redux";
import { getAllBlogs } from "../features/ads/adsSlice";
import CircleImg from "./CircleImg";
import Footer from "./Footer";
import HomeAds from "./HomeAds";
import AdComponent1 from "./AdComponent1";
import Shop from "./shopContent";
import { getAllProducts } from "../features/products/productSlice";
import ProductGroupsContainer from "./ProductGroupsContainer";
import ProductTagSection from "./ProductTagSection";
import { Link } from "react-router-dom";

function Home() {
  const dispatch = useDispatch();
  const { product: allProducts, isSuccess, isLoading } = useSelector((state) => state.product);

  useEffect(() => {
    // Data is now fetched once in App.js
  }, [dispatch]);

  const processedSections = useMemo(() => {
    if (!allProducts || allProducts.length === 0) return null;

    const products = [...allProducts];
    const usedIds = new Set();

    const take = (arr, count) => {
      const taken = arr.filter(p => !usedIds.has(p.id || p._id)).slice(0, count);
      taken.forEach(p => usedIds.add(p.id || p._id));
      return taken;
    };

    const sorted = [...products].sort((a, b) => {
      const aDisc = a.discount > 0 ? 1 : 0;
      const bDisc = b.discount > 0 ? 1 : 0;
      if (bDisc !== aDisc) return bDisc - aDisc;
      return parseInt(b.price) - parseInt(a.price);
    });

    // Smarter distribution: Balance between deals and trends if products are limited
    const availableForGrid = sorted.filter(p => !usedIds.has(p.id || p._id));
    const totalForGrid = Math.min(availableForGrid.length, 12);
    const half = Math.ceil(totalForGrid / 2);

    const deals = take(availableForGrid, half);
    const trends = take(availableForGrid, totalForGrid - half);

    const vip = take(products.filter(p => p.tags?.some(t => t.toLowerCase() === "vip")), 8);
    const flashSale = take(products.filter(p => p.tags?.some(t => t.toLowerCase() === "flash sale")), 8);
    const tenDay = take(products.filter(p => p.tags?.some(t => t.toLowerCase() === "10 day discount")), 8);

    return { deals, trends, vip, flashSale, tenDay, usedIds };
  }, [allProducts]);

  const isOffline = !navigator.onLine;
  if (isOffline) {
    return (
      <div className="flex h-[80vh] items-center justify-center">
        <div className="text-center p-8 bg-white rounded-3xl shadow-2xl border border-gray-100 max-w-sm">
          <div className="text-6xl mb-4">📡</div>
          <h2 className="text-2xl font-black text-gray-900 mb-2 uppercase tracking-tighter">Connection Lost</h2>
          <p className="text-gray-500 text-sm font-medium">Please check your internet connection to browse our pharmaceuticals.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="HomeAll overflow-x-hidden bg-[#fafcfc]">
      <main className="main__content_wrapper">

        {/* Banner Slider */}
        <section>
          <HomeAds />
        </section>

        {/* Category Slider — sticky */}
        <section className="sticky top-[60px] md:top-[60px] z-40 bg-white shadow-sm shadow-teal-900/5 translate-y-[-2px]">
          <CircleImg />
        </section>

        {/* ── Care Suggestions CTA Banner ── */}
        <section className="px-4 lg:px-8 pt-6 pb-2">
          <Link
            to="/care-suggestions"
            style={{
              display: "flex",
              alignItems: "center",
              justifyContent: "space-between",
              background: "linear-gradient(135deg, #0f172a 0%, #134e4a 100%)",
              borderRadius: 20,
              padding: "20px 28px",
              textDecoration: "none",
              maxWidth: 1400,
              margin: "0 auto",
              overflow: "hidden",
              position: "relative",
            }}
          >
            {/* Glow blob */}
            <div style={{
              position: "absolute", right: -20, top: -20,
              width: 180, height: 180,
              borderRadius: "50%",
              background: "radial-gradient(circle, rgba(20,184,166,0.2) 0%, transparent 70%)",
              pointerEvents: "none",
            }} />

            <div style={{ display: "flex", alignItems: "center", gap: 16, zIndex: 1 }}>
              <div style={{
                width: 48, height: 48, borderRadius: 14,
                background: "rgba(20,184,166,0.15)",
                display: "flex", alignItems: "center", justifyContent: "center",
                flexShrink: 0,
              }}>
                <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#2dd4bf" strokeWidth="2"><path d="M22 12h-4l-3 9L9 3l-3 9H2"/></svg>
              </div>
              <div>
                <div style={{ fontSize: 10, fontWeight: 800, color: "#2dd4bf", textTransform: "uppercase", letterSpacing: "0.12em", marginBottom: 4 }}>
                  Smart Health Guide
                </div>
                <div style={{ fontSize: 16, fontWeight: 900, color: "#fff", letterSpacing: "-0.02em", lineHeight: 1.2 }}>
                  Find Expert Health Advice
                </div>
                <div style={{ fontSize: 12, color: "rgba(255,255,255,0.45)", marginTop: 3 }}>
                  Pharmacist-reviewed guides for common conditions
                </div>
              </div>
            </div>

            <div style={{
              display: "flex", alignItems: "center", gap: 8,
              background: "#14b8a6", padding: "10px 20px", borderRadius: 12,
              fontSize: 12, fontWeight: 800, color: "#fff",
              textTransform: "uppercase", letterSpacing: "0.06em",
              whiteSpace: "nowrap", zIndex: 1,
              flexShrink: 0,
            }}>
              Explore
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2.5"><path d="m9 18 6-6-6-6"/></svg>
            </div>
          </Link>
        </section>

        {/* Special Offers */}
        <section className="py-2 bg-white">
          <div className="w-full px-4 lg:px-8">
            <div className="max-w-[1400px] mx-auto">
              <AdComponent1 />
            </div>
          </div>
        </section>

        {/* Product Sections */}
        {processedSections && (
          <>
            <div className="bg-gradient-to-b from-white to-gray-50/50 py-4">
              <ProductGroupsContainer
                deals={processedSections.deals}
                trends={processedSections.trends}
              />
            </div>

            {processedSections.vip.length > 0 && (
              <ProductTagSection
                products={processedSections.vip}
                title="Elite Medical VIP"
                subtitle="Premium Membership"
                icon="💎"
                highlightColor="text-indigo-600"
              />
            )}

            {processedSections.flashSale.length > 0 && (
              <div className="bg-gray-900 py-4">
                <ProductTagSection
                  products={processedSections.flashSale}
                  title="Pulse Rapid Sale"
                  tag="Flash Sale"
                  subtitle="Critical Offers"
                  icon="⚡"
                  highlightColor="text-rose-500"
                />
              </div>
            )}

            {processedSections.tenDay.length > 0 && (
              <ProductTagSection
                products={processedSections.tenDay}
                title="Health Event"
                subtitle="Sequential Care"
                icon="🗓️"
                highlightColor="text-teal-600"
              />
            )}
          </>
        )}

        {/* Full Catalog */}
        <section id="explore-section" className="py-8 bg-white">
          <div className="w-full px-4 lg:px-12 text-center mb-6">
            <span className="text-teal-600 text-[10px] font-black uppercase tracking-widest mb-4 block">Complete Registry</span>
            <h2 className="text-4xl font-black text-gray-900 tracking-tighter uppercase">Explore Full Inventory</h2>
            <p className="text-gray-400 mt-2 text-sm font-medium">Browse our entire clinical catalog with advanced filtering</p>
          </div>
          <Shop />
        </section>

        <Footer />
      </main>
    </div>
  );
}

export default Home;
